/**
 * @param {string} s
 * @return {string}
 */
function solve(s) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u']);

    // 1. Calculate frequency and first appearance index for each vowel present in s
    const frequencies = {};
    const firstAppearance = {};

    for (let i = 0; i < s.length; i++) {
        const char = s[i];
        if (vowels.has(char)) {
            frequencies[char] = (frequencies[char] || 0) + 1;
            if (!(char in firstAppearance)) {
                firstAppearance[char] = i;
            }
        }
    }

    // 2. Determine the order of vowels based on the criteria
    // Criteria:
    // a) Frequency in non-increasing order (descending)
    // b) If frequencies are equal, order by first appearance index (ascending)

    const presentVowels = Object.keys(frequencies).sort(); // Sort keys alphabetically initially, just to iterate consistently

    // Custom sorting logic based on the requirements
    const sortedVowels = [...presentVowels].sort((v1, v2) => {
        const freq1 = frequencies[v1];
        const freq2 = frequencies[v2];

        // Compare frequencies (non-increasing order means freq2 > freq1 comes first)
        if (freq1 !== freq2) {
            return freq2 - freq1; // Descending frequency
        } else {
            // Frequencies are equal, sort by first appearance index (ascending)
            const index1 = firstAppearance[v1];
            const index2 = firstAppearance[v2];
            return index1 - index2; // Ascending index
        }
    });

    // 3. Construct the result string by replacing original vowels with the sorted sequence

    // Create a mapping of original vowel positions to the new sorted vowel sequence
    const newVowelOrder = [];
    for (const vowel of sortedVowels) {
        const count = frequencies[vowel];
        for (let k = 0; k < count; k++) {
            newVowelOrder.push(vowel);
        }
    }

    // Create an array representation of the resulting string
    const resultArr = s.split('');
    let newVowelIndex = 0;

    for (let i = 0; i < s.length; i++) {
        if (vowels.has(s[i])) {
            // This position should be filled by the next vowel from the sorted sequence
            resultArr[i] = newVowelOrder[newVowelIndex];
            newVowelIndex++;
        }
    }

    return resultArr.join('');
}

