use std::collections::HashMap;

fn solve(s: String) -> String {
    let vowels_set: [char; 5] = ['a', 'e', 'i', 'o', 'u'];
    let is_vowel = |c: char| vowels_set.contains(&c);

    // 1. Calculate frequency and first appearance index for each vowel present in s
    let mut frequencies: HashMap<char, i32> = HashMap::new();
    let mut first_appearance: HashMap<char, usize> = HashMap::new();

    for (i, char) in s.chars().enumerate() {
        if is_vowel(char) {
            *frequencies.entry(char).or_insert(0) += 1;
            first_appearance.entry(char).or_insert(i);
        }
    }

    // Collect unique vowels present in s
    let mut present_vowels: Vec<char> = frequencies.keys().cloned().collect();

    // 2. Determine the order of vowels based on the criteria
    // Criteria:
    // a) Frequency in non-increasing order (descending)
    // b) If frequencies are equal, order by first appearance index (ascending)

    present_vowels.sort_by(|&v1, &v2| {
        let freq1 = frequencies[&v1];
        let freq2 = frequencies[&v2];

        // Compare frequencies (non-increasing order -> freq2 vs freq1)
        if freq1 != freq2 {
            // Descending frequency: if freq2 > freq1, v2 comes before v1 (return positive)
            freq2.cmp(&freq1)
        } else {
            // Frequencies are equal, sort by first appearance index (ascending)
            let index1 = first_appearance[&v1];
            let index2 = first_appearance[&v2];
            index1.cmp(&index2)
        }
    });

    // 3. Construct the result string

    // Create the sequence of all vowels in the required order
    let mut new_vowel_order: Vec<char> = Vec::new();
    for &vowel in &present_vowels {
        let count = frequencies[&vowel];
        for _ in 0..count {
            new_vowel_order.push(vowel);
        }
    }

    // Build the result string by replacing original vowels with the sorted sequence
    let mut result_chars: Vec<char> = Vec::with_capacity(s.len());
    let mut new_vowel_idx = 0;

    for char in s.chars() {
        if is_vowel(char) {
            // Replace with the next vowel from the sorted sequence
            result_chars.push(new_vowel_order[new_vowel_idx]);
            new_vowel_idx += 1;
        } else {
            // Keep consonants as they are
            result_chars.push(char);
        }
    }

    result_chars.into_iter().collect()
}
