    present_vowels.sort_by(|&v1, &v2| {
        let freq1 = frequencies[&v1];
        let freq2 = frequencies[&v2];

        // Compare frequencies (non-increasing order: freq2 > freq1 comes first, so return negative if freq2 > freq1)
        match freq2.cmp(&freq1) {
            std::cmp::Ordering::Equal => {
