    // Create the flattened sequence of sorted vowels
    let mut new_vowel_order: Vec<char> = Vec::new();
    for &vowel in &present_vowels {
        let count = *frequencies.get(&vowel).unwrap();
        for _ in 0..count {
            new_vowel_order.push(vowel);
        }
    }

    // Build the result string by replacing original vowels
    let mut result_chars: Vec<char> = s.chars().collect();
    let mut new_vowel_index = 0;

