        let freq1 = *frequencies.get(&v1).unwrap();
        let freq2 = *frequencies.get(&v2).unwrap();

        // Compare frequencies (non-increasing order: freq2 > freq1 comes first, so use cmp_rev)
        match freq2.cmp(&freq1) {
