    // Create a mapping of original vowel positions to the new sorted vowel sequence
    const newVowelOrder = [];
    for (const vowel of sortedVowels) {
        const count = frequencies[vowel];
        for (let k = 0; k < count; k++) {
            newVowelOrder.push(vowel);
